import{_ as a,c as e,o as n,ag as l}from"./chunks/framework.B-XtCDNB.js";const d=JSON.parse('{"title":"Live Queries","description":"","frontmatter":{},"headers":[],"relativePath":"capabilities/live-queries.md","filePath":"capabilities/live-queries.md"}'),o={name:"capabilities/live-queries.md"};function t(p,s,r,i,c,y){return n(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="live-queries" tabindex="-1">Live Queries <a class="header-anchor" href="#live-queries" aria-label="Permalink to &quot;Live Queries&quot;">​</a></h1><p>Live queries let a SQL <code>SELECT</code> stay open and keep its result current as underlying data changes.</p><p>The API is still just <code>query()</code>, but with <code>live</code> turned on:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  &#39;</span><span style="color:#C3E88D;">SELECT id, title FROM public.posts ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>The returned object is a <code>RealtimeResult</code>.</p><h2 id="the-short-version" tabindex="-1">The short version <a class="header-anchor" href="#the-short-version" aria-label="Permalink to &quot;The short version&quot;">​</a></h2><p>Use a live query when you want:</p><ul><li>a query-shaped result</li><li>that keeps updating over time</li><li>without rebuilding that query manually after each write</li></ul><p>That is different from:</p><ul><li><a href="/capabilities/streaming"><code>db.stream()</code></a>, which is about lazy one-time iteration</li><li><a href="/capabilities/changefeeds"><code>db.wal.subscribe()</code></a>, which is about table-level commit events</li></ul><h2 id="what-you-get-back" tabindex="-1">What you get back <a class="header-anchor" href="#what-you-get-back" aria-label="Permalink to &quot;What you get back&quot;">​</a></h2><p>A live query returns a <code>RealtimeResult</code> with:</p><ul><li><code>rows</code>: the current result rows</li><li><code>hashes</code>: internal row identity hashes</li><li><code>mode</code>: delivery mode such as <code>&#39;live&#39;</code>, <code>&#39;streaming&#39;</code>, or <code>&#39;streaming_only&#39;</code></li><li><code>abort()</code>: stop the live query</li></ul><p>Example:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  &#39;</span><span style="color:#C3E88D;">SELECT id, title FROM public.posts ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">mode)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">abort</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>See also: <a href="/docs/query-api#realtimeresult">Query Interface</a></p><h2 id="two-ways-to-consume-live-queries" tabindex="-1">Two ways to consume live queries <a class="header-anchor" href="#two-ways-to-consume-live-queries" aria-label="Permalink to &quot;Two ways to consume live queries&quot;">​</a></h2><h3 id="_1-reactive-rows" tabindex="-1">1. Reactive rows <a class="header-anchor" href="#_1-reactive-rows" aria-label="Permalink to &quot;1. Reactive rows&quot;">​</a></h3><p>The simplest form is to let <code>result.rows</code> update in place.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, title</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.posts</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">table</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span><span style="color:#C3E88D;">INSERT INTO public.posts (id, title) VALUES (3, &#39;New Post&#39;)</span><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">table</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// result.rows now reflects the current query truth</span></span></code></pre></div><p>This is the right model when your application wants the current result itself.</p><h3 id="_2-commit-callback" tabindex="-1">2. Commit callback <a class="header-anchor" href="#_2-commit-callback" aria-label="Permalink to &quot;2. Commit callback&quot;">​</a></h3><p>You can also receive live-query commits explicitly.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> commits </span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> []</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  &#39;</span><span style="color:#C3E88D;">SELECT id, name FROM public.rt_live WHERE id &gt; 1 ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#BABED8;"> commits</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">push</span><span style="color:#BABED8;">(commit)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">mode)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// commonly &#39;streaming&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">abort</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This is useful when you want:</p><ul><li>the live rows</li><li>and explicit access to diff/result commits as they happen</li></ul><h2 id="what-kinds-of-queries-are-supported" tabindex="-1">What kinds of queries are supported <a class="header-anchor" href="#what-kinds-of-queries-are-supported" aria-label="Permalink to &quot;What kinds of queries are supported&quot;">​</a></h2><p>Live mode is currently for <code>SELECT</code> statements with a real <code>FROM</code> clause.</p><p>That means:</p><ul><li>plain table queries</li><li>joins</li><li>filters</li><li>ordering</li><li>limits</li><li>aggregates</li><li>subqueries</li><li>derived tables</li></ul><p>all participate in the live-query model when supported by the runtime and query shape.</p><h2 id="what-happens-when-data-changes" tabindex="-1">What happens when data changes <a class="header-anchor" href="#what-happens-when-data-changes" aria-label="Permalink to &quot;What happens when data changes&quot;">​</a></h2><p>The key idea is:</p><blockquote><p>LinkedQL does not expose &quot;table changes pretending to be query changes.&quot; It maintains the query result itself.</p></blockquote><p>That means inserts, updates, deletes, join transitions, re-ordering, limit-window shifts, and aggregate recalculations are reflected as result-level changes.</p><h3 id="basic-row-changes" tabindex="-1">Basic row changes <a class="header-anchor" href="#basic-row-changes" aria-label="Permalink to &quot;Basic row changes&quot;">​</a></h3><p>Given:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, title</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.posts</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Then:</p><ul><li><code>INSERT</code> may add a row to <code>result.rows</code></li><li><code>UPDATE</code> may mutate an existing row in place</li><li><code>DELETE</code> may remove a row from <code>result.rows</code></li></ul><h3 id="join-transitions" tabindex="-1">Join transitions <a class="header-anchor" href="#join-transitions" aria-label="Permalink to &quot;Join transitions&quot;">​</a></h3><p>For joins, the effect is often subtler.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">    p.id,</span></span>
<span class="line"><span style="color:#C3E88D;">    p.title,</span></span>
<span class="line"><span style="color:#C3E88D;">    u.name AS author_name</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.posts p</span></span>
<span class="line"><span style="color:#C3E88D;">  LEFT JOIN public.users u ON p.author_id = u.id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>If a matching user row appears later, disappears later, or changes, LinkedQL tries to preserve result continuity rather than treating every join transition like a full teardown/rebuild of the row identity.</p><h3 id="ordered-and-limited-windows" tabindex="-1">Ordered and limited windows <a class="header-anchor" href="#ordered-and-limited-windows" aria-label="Permalink to &quot;Ordered and limited windows&quot;">​</a></h3><p>Queries with <code>ORDER BY</code>, <code>LIMIT</code>, and <code>OFFSET</code> keep those semantics live.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT *</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.posts</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY created_at DESC</span></span>
<span class="line"><span style="color:#C3E88D;">  LIMIT 5</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This result keeps representing:</p><blockquote><p>&quot;the newest five posts&quot;</p></blockquote><p>not:</p><blockquote><p>&quot;the five posts that happened to be in the first render&quot;</p></blockquote><h2 id="stopping-a-live-query" tabindex="-1">Stopping a live query <a class="header-anchor" href="#stopping-a-live-query" aria-label="Permalink to &quot;Stopping a live query&quot;">​</a></h2><p>Stop a live query with:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">abort</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>If the live query was created with a stable <code>id</code>, some runtimes also support forgetting the persisted slot state:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  &#39;</span><span style="color:#C3E88D;">SELECT * FROM public.posts ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> id</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">posts_slot</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">abort</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> forget</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h2 id="important-constraints" tabindex="-1">Important constraints <a class="header-anchor" href="#important-constraints" aria-label="Permalink to &quot;Important constraints&quot;">​</a></h2><h3 id="no-live-queries-inside-explicit-transactions" tabindex="-1">No live queries inside explicit transactions <a class="header-anchor" href="#no-live-queries-inside-explicit-transactions" aria-label="Permalink to &quot;No live queries inside explicit transactions&quot;">​</a></h3><p>Live queries are not supported inside explicit transactions.</p><h3 id="live-queries-are-query-level-not-table-level" tabindex="-1">Live queries are query-level, not table-level <a class="header-anchor" href="#live-queries-are-query-level-not-table-level" aria-label="Permalink to &quot;Live queries are query-level, not table-level&quot;">​</a></h3><p>If you care about table mutation events directly, use:</p><ul><li><a href="/capabilities/changefeeds">Changefeeds (WAL)</a></li></ul><p>not live queries.</p><h3 id="mainstream-databases-may-need-setup" tabindex="-1">Mainstream databases may need setup <a class="header-anchor" href="#mainstream-databases-may-need-setup" aria-label="Permalink to &quot;Mainstream databases may need setup&quot;">​</a></h3><p>On runtimes backed by mainstream databases, realtime support depends on the underlying changefeed/WAL setup described in <a href="/docs/setup">Dialects &amp; Clients</a>.</p><h2 id="which-mode-should-you-use" tabindex="-1">Which mode should you use? <a class="header-anchor" href="#which-mode-should-you-use" aria-label="Permalink to &quot;Which mode should you use?&quot;">​</a></h2><p>Use a live query when:</p><ul><li>the UI is driven by a query result</li><li>you want the current result kept correct over time</li><li>joins, limits, or aggregates matter at the result level</li></ul><p>Use <code>wal.subscribe()</code> when:</p><ul><li>you care about table commits directly</li><li>you want to build your own projection logic</li><li>you need raw mutation visibility</li></ul><p>Use <code>stream()</code> when:</p><ul><li>you want lazy one-time iteration over a large result</li></ul><h2 id="reader-s-map" tabindex="-1">Reader&#39;s map <a class="header-anchor" href="#reader-s-map" aria-label="Permalink to &quot;Reader&#39;s map&quot;">​</a></h2><ul><li><a href="/docs/query-api">Query Interface</a></li><li><a href="/capabilities/changefeeds">Changefeeds (WAL)</a></li><li><a href="/capabilities/streaming">Streaming</a></li><li><a href="/engineering/realtime-engine">The Realtime Engine</a></li></ul>`,74)])])}const F=a(o,[["render",t]]);export{d as __pageData,F as default};
